/* global document, Office, fetch, navigator */

const FLASK_URL = "https://localhost:5000/check";

Office.onReady((info) => {
  if (info.host === Office.HostType.Outlook) {
    runCheck();
    document.getElementById("recheck-button").onclick = runCheck;
    document.getElementById("copy-rewrite-button").onclick = copyRewrite;
    document.getElementById("insert-rewrite-button").onclick = insertRewrite;
  }
});

async function runCheck() {
  showLoading();

  try {
    const rawBody = await getDraftBody();
    const { draft, history } = splitDraftAndHistory(rawBody);

    const response = await fetch(FLASK_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        email: draft,
        client_email: history
      })
    });

    if (!response.ok) {
      throw new Error(`Server returned ${response.status}`);
    }

    const result = await response.json();
    renderResult(result);
  } catch (err) {
    showError(`Couldn't reach the Compass service. Make sure Flask is running at ${FLASK_URL}. Details: ${err.message}`);
  }
}

function splitDraftAndHistory(rawBody) {
  // Splits a reply body into the user's typed portion and the quoted history.
  // Outlook on web, desktop, and mobile all use slightly different markers, so we
  // try several patterns and cut at whichever appears earliest in the text.
  if (!rawBody) return { draft: "", history: "" };

  const markers = [
    /\n\s*From:\s.+\nSent:/i,                  // Outlook desktop classic
    /\n\s*On .+ wrote:/i,                       // Outlook web / Gmail style
    /\n\s*On .+,.+ at .+ wrote:/i,              // Outlook web alternate
    /\n\s*-----Original Message-----/i,         // Older Outlook
    /\n\s*________________________________/,    // Outlook horizontal rule
    /\n\s*Sent from my iPhone/i,                // Mobile signature boundary
    /\nFrom: .+@.+\..+/i                        // Loose fallback: From: line with email
  ];

  let earliest = rawBody.length;
  for (const marker of markers) {
    const match = rawBody.match(marker);
    if (match && match.index < earliest) {
      earliest = match.index;
    }
  }

  return {
    draft: rawBody.substring(0, earliest).trim(),
    history: rawBody.substring(earliest).trim()
  };
}

function getDraftBody() {
  return new Promise((resolve, reject) => {
    Office.context.mailbox.item.body.getAsync(
      Office.CoercionType.Text,
      (asyncResult) => {
        if (asyncResult.status === Office.AsyncResultStatus.Succeeded) {
          resolve(asyncResult.value || "");
        } else {
          reject(new Error("Couldn't read the draft body."));
        }
      }
    );
  });
}

function showLoading() {
  document.getElementById("status-section").style.display = "block";
  document.getElementById("results-section").style.display = "none";
  document.getElementById("error-section").style.display = "none";
  document.getElementById("recheck-button").style.display = "none";
}

function showError(message) {
  document.getElementById("status-section").style.display = "none";
  document.getElementById("results-section").style.display = "none";
  document.getElementById("error-section").style.display = "block";
  document.getElementById("error-text").textContent = message;
  document.getElementById("recheck-button").style.display = "block";
}

function renderResult(result) {
  document.getElementById("status-section").style.display = "none";
  document.getElementById("error-section").style.display = "none";
  document.getElementById("results-section").style.display = "block";
  document.getElementById("recheck-button").style.display = "block";

  const statusEl = document.getElementById("overall-status");
  const status = (result.overall_status || "GREEN").toUpperCase();
  statusEl.className = "overall-status " + status.toLowerCase();

  const statusLabels = {
    RED: "🛑 Do not send — needs your attention",
    AMBER: "⚠️ Review before sending",
    GREEN: "✅ Looks good"
  };
  statusEl.textContent = statusLabels[status] || status;

  renderFlagGroup("red-flags-block", "red-flags-list", result.red_flags || []);
  renderFlagGroup("amber-flags-block", "amber-flags-list", result.amber_flags || []);
  renderFlagGroup("positive-notes-block", "positive-notes-list", result.positive_notes || []);

  renderSuggestedDraft(result.suggested_draft || "");
}

function renderFlagGroup(blockId, listId, items) {
  const block = document.getElementById(blockId);
  const list = document.getElementById(listId);
  list.innerHTML = "";

  if (!items || items.length === 0) {
    block.style.display = "none";
    return;
  }

  block.style.display = "block";

  items.forEach((item) => {
    const li = document.createElement("li");
    const primaryText = item.issue || item.note || "(no text)";
    const secondaryText = item.action || "";

    const issueDiv = document.createElement("div");
    issueDiv.className = "flag-issue";
    issueDiv.textContent = primaryText;
    li.appendChild(issueDiv);

    if (secondaryText) {
      const actionDiv = document.createElement("div");
      actionDiv.className = "flag-action";
      actionDiv.textContent = secondaryText;
      li.appendChild(actionDiv);
    }

    list.appendChild(li);
  });
}

function renderSuggestedDraft(draftText) {
  const block = document.getElementById("suggested-draft-block");
  const textEl = document.getElementById("suggested-draft-text");

  if (!draftText || !draftText.trim()) {
    block.style.display = "none";
    return;
  }

  textEl.textContent = draftText;
  block.style.display = "block";
}

function copyRewrite() {
  const text = document.getElementById("suggested-draft-text").textContent;
  if (!text) return;

  const btn = document.getElementById("copy-rewrite-button");
  const originalText = btn.textContent;

  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(
      () => {
        btn.textContent = "Copied ✓";
        setTimeout(() => { btn.textContent = originalText; }, 1500);
      },
      () => {
        btn.textContent = "Copy failed";
        setTimeout(() => { btn.textContent = originalText; }, 1500);
      }
    );
  } else {
    const temp = document.createElement("textarea");
    temp.value = text;
    document.body.appendChild(temp);
    temp.select();
    try {
      document.execCommand("copy");
      btn.textContent = "Copied ✓";
    } catch (e) {
      btn.textContent = "Copy failed";
    }
    document.body.removeChild(temp);
    setTimeout(() => { btn.textContent = originalText; }, 1500);
  }
}

function insertRewrite() {
  const text = document.getElementById("suggested-draft-text").textContent;
  if (!text) return;

  const btn = document.getElementById("insert-rewrite-button");
  const originalText = btn.textContent;
  btn.disabled = true;
  btn.textContent = "Inserting...";

  // Read body as HTML so we can preserve the quoted email thread.
  // Outlook auto-inserts the user's signature and quoted history in HTML;
  // if we replace with plain text we'd lose both.
  Office.context.mailbox.item.body.getAsync(
    Office.CoercionType.Html,
    (htmlResult) => {
      if (htmlResult.status !== Office.AsyncResultStatus.Succeeded) {
        finishInsert(btn, originalText, false, "Read failed");
        return;
      }

      const htmlBody = htmlResult.value || "";
      const quotedHtml = extractQuotedHtml(htmlBody);

      // Wrap the AI rewrite in basic <p> tags so paragraphs render correctly.
      const rewriteHtml = formatRewriteAsHtml(text);

      // Combine: rewritten user portion + (preserved) quoted email thread.
      // Note: this strategy loses the signature, since the signature sits
      // between the user's typed content and the quoted history. Users may
      // need to re-insert their signature manually via Outlook's Signature
      // ribbon button. Trade-off is conscious — preserving the email thread
      // is more critical than preserving signature for reply context.
      const newBody = quotedHtml
        ? rewriteHtml + quotedHtml
        : rewriteHtml;

      Office.context.mailbox.item.body.setAsync(
        newBody,
        { coercionType: Office.CoercionType.Html },
        (setResult) => {
          const ok = setResult.status === Office.AsyncResultStatus.Succeeded;
          finishInsert(btn, originalText, ok, ok ? "Inserted ✓" : "Insert failed");
        }
      );
    }
  );
}

function finishInsert(btn, originalText, ok, message) {
  btn.disabled = false;
  btn.textContent = message;
  setTimeout(() => { btn.textContent = originalText; }, 1800);
}

function formatRewriteAsHtml(text) {
  // Split rewrite into paragraphs on double newlines; preserve single
  // line breaks within a paragraph using <br>. Escape HTML special chars
  // so any <, >, & in the AI output don't break the resulting HTML.
  return text
    .split(/\n{2,}/)
    .map((paragraph) => {
      const escaped = paragraph
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/"/g, "&quot;")
        .replace(/'/g, "&#039;");
      return `<p>${escaped.replace(/\n/g, "<br>")}</p>`;
    })
    .join("");
}

function extractQuotedHtml(htmlBody) {
  // Find where the quoted email thread begins inside the HTML body.
  // Outlook uses different markers across web/desktop/mobile, so we try
  // multiple patterns and cut at whichever appears earliest.
  // Returns the substring from the marker to the end of the body, or
  // empty string if this is a new compose (no reply context).
  if (!htmlBody) return "";

  const patterns = [
    /<div[^>]*id=["']?divRplyFwdMsg["']?[^>]*>/i,
    /<div[^>]*id=["']?appendonsend["']?[^>]*>/i,
    /<div[^>]*class=["']?[^"']*OutlookMessageHeader[^"']*["']?[^>]*>/i,
    /<div[^>]*class=["']?[^"']*x_OutlookMessageHeader[^"']*["']?[^>]*>/i,
    /<hr[^>]*id=["']?stopSpelling["']?[^>]*>/i,
    /<hr[^>]*tabindex=["']?-1["']?[^>]*>/i,
    /<blockquote[^>]*type=["']?cite["']?[^>]*>/i,
    /<div[^>]*style=["'][^"']*border-top:[^"']*solid[^"']*["'][^>]*>(?=[\s\S]{0,500}From:)/i,
    /<p[^>]*>\s*<b[^>]*>\s*From:\s*<\/b>/i,
    /<p[^>]*>\s*From:\s.+@.+<\/p>/i
  ];

  let earliestIndex = -1;
  for (const pattern of patterns) {
    const match = htmlBody.match(pattern);
    if (match && match.index !== undefined) {
      if (earliestIndex === -1 || match.index < earliestIndex) {
        earliestIndex = match.index;
      }
    }
  }

  return earliestIndex >= 0 ? htmlBody.substring(earliestIndex) : "";
}
